-- Tablevoice Phase 8: controlled autopilot
create table public.automation_policies(id uuid primary key default gen_random_uuid(),restaurant_id uuid not null references public.restaurants(id) on delete cascade,version integer not null,status text not null check(status in('draft','shadow','active','paused','revoked')),level integer not null check(level between 0 and 3),allowed_sources text[] not null,allowed_categories text[] not null,allowed_languages text[] not null,max_risk text not null check(max_risk='green'),voice_profile_id uuid not null references public.voice_profiles(id),voice_profile_version integer not null,prompt_version text not null,model text not null,minimum_shadow_decisions integer not null,minimum_agreement_rate numeric not null check(minimum_agreement_rate between 0 and 1),consent_evidence text,consented_by uuid references auth.users(id),consented_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(restaurant_id,version));
create table public.automation_shadow_decisions(id uuid primary key default gen_random_uuid(),restaurant_id uuid not null references public.restaurants(id) on delete cascade,policy_id uuid not null references public.automation_policies(id) on delete cascade,review_id uuid not null references public.reviews(id) on delete cascade,eligible boolean not null,reason text not null,proposed_action text not null,human_decision text,agreed boolean,created_at timestamptz not null default now());
create table public.automation_executions(id uuid primary key default gen_random_uuid(),restaurant_id uuid not null references public.restaurants(id) on delete cascade,policy_id uuid not null references public.automation_policies(id) on delete cascade,review_id uuid not null references public.reviews(id) on delete cascade,idempotency_key text not null,action text not null,status text not null check(status in('blocked','executed','failed')),reason text not null,created_at timestamptz not null default now(),completed_at timestamptz,unique(restaurant_id,idempotency_key));
create table public.automation_kill_switches(id uuid primary key default gen_random_uuid(),restaurant_id uuid not null references public.restaurants(id) on delete cascade,scope text not null check(scope in('restaurant','global')),active boolean not null,reason text not null,activated_by uuid not null references auth.users(id),activated_at timestamptz not null,cleared_by uuid references auth.users(id),cleared_at timestamptz,unique(restaurant_id,scope));
alter table public.automation_policies enable row level security;alter table public.automation_shadow_decisions enable row level security;alter table public.automation_executions enable row level security;alter table public.automation_kill_switches enable row level security;
-- Server-only automation records; no client policy and all writes remain feature-gated.
